    const normalizedStr = str.replace(/[^a-zA-Z0-9]/g, '').toLowerCase();

    // Step 2: Reverse the normalized string
    const reversedStr = normalizedStr.split('').reverse().join('');

    // Step 3: Compare the normalized string with its reversed version
    return normalizedStr === reversedStr;
}

// Test cases
console.log(isPalindrome("racecar")); // returns true
console.log(isPalindrome("hello")); // returns false
console.log(isPalindrome("A man, a plan, a canal, Panama")); // returns true
console.log(isPalindrome("No 'x' in Nixon")); // returns true

